1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	const COMPONENT_BASE = 25;
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE = 60;
34	
35	const FIRST_INSURANCE_RATE = 0.1;
36	const CURSE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const LOYALTY_RATE = 0.2;
40	const LOYALTY_THRESHOLD = 2;
41	const PROCESSING_FEE = 5;
42	const ROUNDING_PRECISION = 6;
43	
44	const componentGroupBase = (count: number): number =>
45	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
46	
47	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
48	
49	const withSurcharge = (base: number, rate: number): number => base + base * rate;
50	
51	const isHighlyEnchanted = (item: Item): boolean =>
52	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
53	
54	const itemSurchargeRate = (item: Item): number =>
55	  FIRST_INSURANCE_RATE +
56	  (item.cursed ? CURSE_RATE : 0) +
57	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
58	
59	const mainItemPremium = (item: Item): number =>
60	  withSurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
61	
62	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
63	
64	const mainItemBaseSum = (items: Item[]): number =>
65	  mainItems(items).reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
66	
67	const mainItemTotal = (items: Item[]): number =>
68	  mainItems(items).reduce((sum, item) => sum + mainItemPremium(item), 0);
69	
70	const componentBaseSum = (items: Item[]): number => {
71	  const counts: Record<string, number> = {};
72	  for (const item of items.filter(isComponent)) {
73	    counts[item.type] = (counts[item.type] ?? 0) + 1;
74	  }
75	  return Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
76	};
77	
78	const componentTotal = (items: Item[]): number =>
79	  withSurcharge(componentBaseSum(items), FIRST_INSURANCE_RATE);
80	
81	const policyBase = (items: Item[]): number => mainItemBaseSum(items) + componentBaseSum(items);
82	
83	const loyaltyDiscount = (items: Item[], customer: Customer): number =>
84	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? LOYALTY_RATE * policyBase(items) : 0;
85	
86	const roundUpToWhole = (amount: number): number =>
87	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
88	
89	const itemPremiumSum = (items: Item[]): number =>
90	  mainItemTotal(items) + componentTotal(items);
91	
92	const quotePremium = (items: Item[], customer: Customer): number =>
93	  roundUpToWhole(
94	    itemPremiumSum(items) - loyaltyDiscount(items, customer) + PROCESSING_FEE,
95	  );
96	
97	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
98	  const results = scenario.steps.map((step) => ({
99	    premium: quotePremium(step.items, scenario.customer),
100	  }));
101	  return { results };
102	};
